import Map from "ol/Map.js";
import View from "ol/View.js";
import TileLayer from "ol/layer/Tile.js";
import WebGLTileLayer from "ol/layer/WebGLTile.js";
import VectorLayer from "ol/layer/Vector.js";
import VectorSource from "ol/source/Vector.js";
import GeoJSON from "ol/format/GeoJSON.js";
import GeoTIFF from "ol/source/GeoTIFF.js";
import OSM from "ol/source/OSM.js";
import Overlay from "ol/Overlay.js";
import { fromLonLat, transformExtent } from "ol/proj.js";
import ScaleLine from "ol/control/ScaleLine.js";
import MousePosition from "ol/control/MousePosition.js";
import ZoomToExtent from "ol/control/ZoomToExtent.js";
import { createStringXY } from "ol/coordinate.js";
import { Fill, Stroke, Style, Circle as CircleStyle } from "ol/style.js";

// 1. Granica područja

const mapaExtent = transformExtent(
  [20.28, 44.71, 20.62, 44.89],
  "EPSG:4326",
  "EPSG:3857",
);

// 2.a ) OSM i Rasterski lejeri

const osmLayer = new TileLayer({ source: new OSM() });
const cogLayer = new WebGLTileLayer({
  source: new GeoTIFF({
    normalize: true,
    sources: [{ url: "/data/sentinel_natural_color.tif" }],
  }),
});

// 2. b) Vektorski lejeri

const poiLayer = new VectorLayer({
  source: new VectorSource({
    url: "./data/znamenitosti.geojson",
    format: new GeoJSON(),
  }),
  style: new Style({
    image: new CircleStyle({
      radius: 7,
      fill: new Fill({ color: "#e74c3c" }),
      stroke: new Stroke({ color: "#ffffff", width: 2 }),
    }),
  }),
});

const riverLayer = new VectorLayer({
  source: new VectorSource({
    url: "./data/reke.geojson",
    format: new GeoJSON(),
  }),
  style: new Style({
    fill: new Fill({ color: "#74b9ff" }),
    stroke: new Stroke({ color: "#74b9ff", width: 1.5 }),
  }),
});

const parksLayer = new VectorLayer({
  source: new VectorSource({
    url: "./data/parkovi.geojson",
    format: new GeoJSON(),
  }),
  style: new Style({
    fill: new Fill({ color: "rgba(46, 204, 113, 0.4)" }),
    stroke: new Stroke({ color: "#2ecc71", width: 1 }),
  }),
});

const forestLayer = new VectorLayer({
  source: new VectorSource({
    url: "./data/sume.geojson",
    format: new GeoJSON(),
  }),
  style: new Style({
    fill: new Fill({ color: "rgba(39, 174, 96, 0.5)" }),
    stroke: new Stroke({ color: "#27ae60", width: 1 }),
  }),
});

const highwayLayer = new VectorLayer({
  source: new VectorSource({
    url: "./data/putevi.geojson",
    format: new GeoJSON(),
  }),
  style: new Style({ stroke: new Stroke({ color: "#e67e22", width: 2 }) }),
});

const railwayLayer = new VectorLayer({
  source: new VectorSource({
    url: "./data/pruge.geojson",
    format: new GeoJSON(),
  }),
  style: new Style({
    stroke: new Stroke({ color: "#7f8c8d", width: 2, lineDash: [6, 4] }),
  }),
});

// 3. Interakcija

const container = document.getElementById("popup");
const content = document.getElementById("popup-content");
const overlay = new Overlay({ element: container, autoPan: false });

// 4. Inicijalizacija mape

const map = new Map({
  target: "map-container",
  layers: [
    osmLayer,
    cogLayer,
    forestLayer,
    parksLayer,
    riverLayer,
    railwayLayer,
    highwayLayer,
    poiLayer,
  ],
  overlays: [overlay],
  view: new View({
    center: fromLonLat([20.4572, 44.7872]),
    zoom: 14,
    minZoom: 13,
    maxZoom: 19,
    extent: mapaExtent,
    showFullExtent: true,
  }),
});

map.addControl(new ScaleLine({ units: "metric" }));
map.addControl(
  new MousePosition({
    coordinateFormat: createStringXY(4),
    projection: "EPSG:4326",
    target: "mouse-position",
  }),
);
map.addControl(new ZoomToExtent({ extent: mapaExtent }));

// 5. Promena lejera (lejer svičer)

const layerSwitcher = (id, instance) => {
  document
    .getElementById(id)
    .addEventListener("change", (e) => instance.setVisible(e.target.checked));
};
layerSwitcher("chk-osm", osmLayer);
layerSwitcher("chk-cog", cogLayer);
layerSwitcher("chk-poi", poiLayer);
layerSwitcher("chk-river", riverLayer);
layerSwitcher("chk-parks", parksLayer);
layerSwitcher("chk-forest", forestLayer);
layerSwitcher("chk-highway", highwayLayer);
layerSwitcher("chk-railway", railwayLayer);

// 6. Funkcionalnost

map.on("pointermove", (evt) => {
  if (evt.dragging) return;

  const feature = map.forEachFeatureAtPixel(evt.pixel, (f) => f, {
    layerFilter: (layer) => layer !== osmLayer && layer !== cogLayer,
  });

  map.getTargetElement().style.cursor = feature ? "pointer" : "";

  if (feature) {
    let title = feature.get("name:sr") || feature.get("name");
    if (
      !title &&
      (feature.get("waterway") || feature.get("natural") === "water")
    ) {
      title =
        evt.coordinate[1] > 5594000 || evt.coordinate[0] >= 2276500
          ? "Дунав"
          : "Сава";
    }

    if (title) {
      content.textContent = title;
      container.style.display = "block";
      overlay.setPosition(evt.coordinate);
      return;
    }
  }

  overlay.setPosition(undefined);
});
